# Geometry module - shapes and area calculations

class Shape:
    name: str
    _id: int

    def __init__(self, name: str, id: int):
        self.name = name
        self._id = id

    @virtual
    def get_display_name(self) -> str:
        return self.name

    @virtual
    def area(self) -> float:
        return 0.0

    @virtual
    def perimeter(self) -> float:
        return 0.0

    @virtual
    def describe(self) -> str:
        return "Shape: " + self.name

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, name: str, id: int, width: float, height: float):
        super().__init__(name, id)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def describe(self) -> str:
        return "Rectangle: " + self.name

class Circle(Shape):
    radius: float

    def __init__(self, name: str, id: int, radius: float):
        super().__init__(name, id)
        self.radius = radius

    @override
    def area(self) -> float:
        PI: float = 3.14159265358979323846
        return PI * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        PI: float = 3.14159265358979323846
        return 2.0 * PI * self.radius

    @override
    def describe(self) -> str:
        return "Circle: " + self.name

