# Shape renderer module
from graphics import Color, Point, IRenderable
from geometry import Shape, Rectangle, Circle

class RenderableRectangle(Rectangle, IRenderable):
    position: Point

    def __init__(self, name: str, id: int, width: float, height: float, x: float, y: float):
        super().__init__(name, id, width, height)
        self.position = Point(x, y)

    def render(self, color: Color) -> str:
        return "Rendering " + self.name + " at (" + str(self.position.x) + ", " + str(self.position.y) + ") with color " + color.name

class RenderableCircle(Circle, IRenderable):
    center: Point

    def __init__(self, name: str, id: int, radius: float, x: float, y: float):
        super().__init__(name, id, radius)
        self.center = Point(x, y)

    def render(self, color: Color) -> str:
        return "Rendering " + self.name + " centered at (" + str(self.center.x) + ", " + str(self.center.y) + ") with color " + color.name

def calculate_total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for shape in shapes:
        total += shape.area()
    return total
